import{Hfs}from"@humanfs/core";import path from"node:path";import{Retrier}from"@humanwhocodes/retry";import nativeFsp from"node:fs/promises";import{fileURLToPath}from"node:url";const RETRY_ERROR_CODES=new Set(["ENFILE","EMFILE"]);class NodeHfsDirectoryEntry{name;isFile;isDirectory;isSymlink;constructor(dirent){this.name=dirent.name;this.isFile=dirent.isFile();this.isDirectory=dirent.isDirectory();this.isSymlink=dirent.isSymbolicLink();}}
export class NodeHfsImpl{#fsp;#retrier;constructor({fsp=nativeFsp}={}){this.#fsp=fsp;this.#retrier=new Retrier(error=>RETRY_ERROR_CODES.has(error.code));}
bytes(filePath){return this.#retrier.retry(()=>this.#fsp.readFile(filePath)).then(buffer=>new Uint8Array(buffer.buffer)).catch(error=>{if(error.code==="ENOENT"){return undefined;}
throw error;});}
async write(filePath,contents){const value=Buffer.from(contents);return this.#retrier.retry(()=>this.#fsp.writeFile(filePath,value)).catch(error=>{if(error.code==="ENOENT"){const dirPath=path.dirname(filePath instanceof URL?fileURLToPath(filePath):filePath,);return this.#fsp.mkdir(dirPath,{recursive:true}).then(()=>this.#fsp.writeFile(filePath,value));}
throw error;});}
async append(filePath,contents){const value=Buffer.from(contents);return this.#retrier.retry(()=>this.#fsp.appendFile(filePath,value)).catch(error=>{if(error.code==="ENOENT"){const dirPath=path.dirname(filePath instanceof URL?fileURLToPath(filePath):filePath,);return this.#fsp.mkdir(dirPath,{recursive:true}).then(()=>this.#fsp.appendFile(filePath,value));}
throw error;});}
isFile(filePath){return this.#fsp.stat(filePath).then(stat=>stat.isFile()).catch(error=>{if(error.code==="ENOENT"){return false;}
throw error;});}
isDirectory(dirPath){return this.#fsp.stat(dirPath).then(stat=>stat.isDirectory()).catch(error=>{if(error.code==="ENOENT"){return false;}
throw error;});}
async createDirectory(dirPath){await this.#fsp.mkdir(dirPath,{recursive:true});}
delete(fileOrDirPath){return this.#fsp.rm(fileOrDirPath).then(()=>true).catch(error=>{if(error.code==="ERR_FS_EISDIR"){return this.#fsp.rmdir(fileOrDirPath).then(()=>true);}
if(error.code==="ENOENT"){return false;}
throw error;});}
deleteAll(fileOrDirPath){return this.#fsp.rm(fileOrDirPath,{recursive:true}).then(()=>true).catch(error=>{if(error.code==="ENOENT"){return false;}
throw error;});}
async*list(dirPath){const entries=await this.#fsp.readdir(dirPath,{withFileTypes:true,});for(const entry of entries){yield new NodeHfsDirectoryEntry(entry);}}
size(filePath){return this.#fsp.stat(filePath).then(stat=>stat.size).catch(error=>{if(error.code==="ENOENT"){return undefined;}
throw error;});}
lastModified(fileOrDirPath){return this.#fsp.stat(fileOrDirPath).then(stat=>stat.mtime).catch(error=>{if(error.code==="ENOENT"){return undefined;}
throw error;});}
async copy(source,destination){const stat=await this.#fsp.lstat(source);if(stat.isSymbolicLink()){const target=await this.#fsp.readlink(source);return this.#fsp.symlink(target,destination);}
return this.#fsp.copyFile(source,destination);}
async copyAll(source,destination){if(await this.isFile(source)){return this.copy(source,destination);}
const sourceStr=source instanceof URL?fileURLToPath(source):source;const destinationStr=destination instanceof URL?fileURLToPath(destination):destination;await this.createDirectory(destination);for await(const entry of this.list(source)){const fromEntryPath=path.join(sourceStr,entry.name);const toEntryPath=path.join(destinationStr,entry.name);if(entry.isSymlink){const target=await this.#fsp.readlink(fromEntryPath);await this.#fsp.symlink(target,toEntryPath);}else if(entry.isDirectory){await this.copyAll(fromEntryPath,toEntryPath);}else{await this.copy(fromEntryPath,toEntryPath);}}}
move(source,destination){return this.#fsp.stat(source).then(stat=>{if(stat.isDirectory()){throw new Error(`EISDIR: illegal operation on a directory, move '${source}' -> '${destination}'`,);}
return this.#fsp.rename(source,destination);});}
async moveAll(source,destination){return this.#fsp.rename(source,destination);}}
export class NodeHfs extends Hfs{constructor({fsp}={}){super({impl:new NodeHfsImpl({fsp})});}}
export const hfs=new NodeHfs();